// Inserts the recipes generated by generate-library-gap-recipes.mjs into the
// live DB and appends them to seed-recipes.json, so both the running app and
// a future fresh-install re-seed pick them up.
//
// Household-owned like every recipe post-d3c59d9 (household-owned recipes +
// Discover/import) — inserted under the real Madruga House household
// (resolved dynamically by the same "join household_members -> auth.users"
// pattern recipes-household-ownership.sql's own backfill used), not the
// reserved Recipe Library system household. That reserved household is
// earmarked for fresh-install re-seeds specifically (see its migration
// comment) — the actual seed library physically lives under Madruga House
// today, so new organic library content matches that, same as
// apply-recipe-dietary-style.mjs's existing rows.
//
// is_seed: false (new content, not part of the original 41 — keeps future
// is_seed-scoped backfill scripts from picking these up by accident).
// Run with: node --env-file=.env.local scripts/apply-library-gap-recipes.mjs

import { createClient } from "@supabase/supabase-js";
import { readFileSync, writeFileSync } from "fs";
import { fileURLToPath } from "url";
import path from "path";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const seedPath = path.join(__dirname, "..", "seed-recipes.json");
const genPath = path.join(__dirname, "generate-library-gap-recipes-output.json");

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const secretKey = process.env.SUPABASE_SECRET_KEY;

if (!supabaseUrl || !secretKey) {
  console.error(
    "Missing NEXT_PUBLIC_SUPABASE_URL or SUPABASE_SECRET_KEY. Run with: node --env-file=.env.local scripts/apply-library-gap-recipes.mjs"
  );
  process.exit(1);
}

const supabase = createClient(supabaseUrl, secretKey);

const seedData = JSON.parse(readFileSync(seedPath, "utf-8"));
const generated = JSON.parse(readFileSync(genPath, "utf-8"));

if (generated.length === 0) {
  console.log("No generated recipes to apply.");
  process.exit(0);
}

const { data: owner, error: ownerError } = await supabase
  .from("household_members")
  .select("household_id, households!inner(name)")
  .eq("households.name", "Madruga House")
  .limit(1)
  .maybeSingle();

if (ownerError || !owner) {
  console.error("Could not resolve Madruga House's household_id:", ownerError?.message ?? "not found");
  process.exit(1);
}
const householdId = owner.household_id;

// Insert into the live DB first so we have real ids to append to
// seed-recipes.json.
const rows = generated.map((r) => ({
  name: r.name,
  category: r.category,
  cuisines: r.cuisines,
  dietary_style: r.dietary_style,
  emoji: r.emoji,
  hint: r.hint,
  recipe: null,
  steps: r.steps,
  prep_time_minutes: r.prep_time_minutes,
  servings: r.servings,
  protein: r.protein,
  fiber: r.fiber,
  cal: r.cal,
  tags: r.tags,
  ingredients: r.ingredients,
  household_id: householdId,
  is_public: true,
  is_seed: false,
  is_ai_generated: true,
  created_by: null,
}));

const { data: inserted, error: insertError } = await supabase
  .from("recipes")
  .insert(rows)
  .select("id, name");

if (insertError) {
  console.error("DB insert failed:", insertError.message);
  process.exit(1);
}
console.log(`Inserted ${inserted.length} new recipe(s) into the live DB.`);

// Append to seed-recipes.json in its existing shape (cat/cuisine singular,
// not category/cuisines[]) with fresh seed-time ids continuing the existing
// s1..s41 sequence.
const existingIds = seedData.recipes.map((r) => r.id);
const maxNum = Math.max(...existingIds.map((id) => parseInt(id.replace("s", ""), 10)));

let nextNum = maxNum + 1;
for (const r of generated) {
  seedData.recipes.push({
    id: `s${nextNum++}`,
    cat: r.category,
    emoji: r.emoji,
    name: r.name,
    hint: r.hint,
    cuisine: r.cuisines[0] ?? null,
    tags: r.tags,
    recipe: null,
    protein: r.protein,
    fiber: r.fiber,
    cal: r.cal,
    ingredients: r.ingredients,
    steps: r.steps,
    prep_time_minutes: r.prep_time_minutes,
    servings: r.servings,
    dietary_style: r.dietary_style,
  });
}

writeFileSync(seedPath, JSON.stringify(seedData, null, 2) + "\n");
console.log(`Appended ${generated.length} recipe(s) to seed-recipes.json.`);
console.log(
  "\nNote: quantity_value/quantity_unit weren't set on these new ingredients — run " +
    "scripts/backfill-quantity-values.mjs + apply-quantity-values.mjs next to fill them in, same as any other recipe missing them."
);
